jsLib:
function getBase(){return 'https://fq-tt-worker.ch6vip.workers.dev';}
function enc(v){return encodeURIComponent(String(v==null?'':v));}
function html(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function clean(s){return String(s==null?'':s).replace(/<\/?em>/g,'').replace(/<[^>]+>/g,'');}
function getBaseUrl(){return typeof baseUrl==='undefined'?'':String(baseUrl||'');}
function param(name){var m=getBaseUrl().match(new RegExp('[?&]'+name+'=([^&]*)'));return m?decodeURIComponent(m[1]):'';}
function buildBookUrl(b){return getBase()+'/?api=book&book_id='+enc(b.book_id)+'&name='+enc(b.book_name||b.raw_book_name||'')+'&author='+enc(b.author||'')+'&cover='+enc(b.thumb_url||b.detail_page_thumb_url||'')+'&intro='+enc(b.abstract||b.book_abstract_v2||'')+'&kind='+enc(b.category||b.pure_category_tags||'')+'&word='+enc(b.word_number||'')+'&last='+enc(b.last_chapter_title||'');}
function normalizeSearch(payload){var root=(payload&&payload.data)||payload||{};var tabs=root.search_tabs||[];var out=[];var seen={};for(var i=0;i<tabs.length;i++){var list=tabs[i].data||[];for(var j=0;j<list.length;j++){var cell=list[j]||{};var books=cell.book_data||[];for(var k=0;k<books.length;k++){var b=books[k]||{};if(!b.book_id||seen[b.book_id])continue;seen[b.book_id]=1;b.bookUrl=buildBookUrl(b);out.push(b);}}}return out;}
function b64Encode(input){var chars='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=';var str=String(input||'');var out='',i=0;while(i<str.length){var c1=str.charCodeAt(i++),c2=str.charCodeAt(i++),c3=str.charCodeAt(i++);var e1=c1>>2,e2=((c1&3)<<4)|(c2>>4),e3=((c2&15)<<2)|(c3>>6),e4=c3&63;if(isNaN(c2)){e3=e4=64;}else if(isNaN(c3)){e4=64;}out+=chars.charAt(e1)+chars.charAt(e2)+chars.charAt(e3)+chars.charAt(e4);}return out;}
function b64Decode(input){var chars='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=';var str=String(input||'').replace(/[^A-Za-z0-9+\/=]/g,'');var out='',i=0;while(i<str.length){var e1=chars.indexOf(str.charAt(i++)),e2=chars.indexOf(str.charAt(i++)),e3=chars.indexOf(str.charAt(i++)),e4=chars.indexOf(str.charAt(i++));var c1=(e1<<2)|(e2>>4),c2=((e2&15)<<4)|(e3>>2),c3=((e3&3)<<6)|e4;if(e1>=0&&e2>=0)out+=String.fromCharCode(c1);if(e3>=0&&e3!==64)out+=String.fromCharCode(c2);if(e4>=0&&e4!==64)out+=String.fromCharCode(c3);}return out;}
function chapterDataUrl(meta){return 'data:;base64,'+b64Encode(JSON.stringify(meta))+',{"type":"fq-tt-worker"}';}
function parseMetaText(s){try{return JSON.parse(String(s||''));}catch(e){}if(/^\d+$/.test(String(s||'')))return {item_id:String(s)};return {};}
function hasMeta(meta){return !!(meta&&(meta.book_id||meta.bookId||meta.item_id||meta.itemId||meta.item_ids));}
function decodeChapterMeta(raw){var original=String(raw||'');var meta=parseMetaText(original);if(hasMeta(meta))return meta;var marker='base64,';var pos=original.indexOf(marker);if(pos>=0){var body=original.substring(pos+marker.length);var comma=body.indexOf(',');if(comma>=0)body=body.substring(0,comma);meta=parseMetaText(b64Decode(body));if(hasMeta(meta))return meta;try{meta=parseMetaText(java.hexDecodeToString(body));if(hasMeta(meta))return meta;}catch(e){}}try{meta=parseMetaText(java.hexDecodeToString(original));if(hasMeta(meta))return meta;}catch(e2){}var plain=original;var cut=plain.indexOf(',');if(cut>=0)plain=plain.substring(0,cut);meta=parseMetaText(b64Decode(plain));return meta;}
function commentPageUrl(bookId,itemId,paraIndex){return getBase()+'/?api=comment_page&book_id='+enc(bookId)+'&item_id='+enc(itemId)+'&para_index='+enc(paraIndex||'0')+'&offset=0&count=100';}
function openComment(bookId,itemId,paraIndex,paraText){java.showBrowser(commentPageUrl(bookId,itemId,paraIndex),null,null,JSON.stringify({isHideable:true,expandedCornersRadius:12,skipCollapsed:true,hardwareAccelerated:true,heightPercentage:0.8}));}
function hasCommentMarker(line,bookId,itemId,p){return String(line||'').indexOf('bookSource:fqtt:'+bookId+':'+itemId+':'+p)>=0;}
function commentIcon(bookId,itemId,p,text){var url=commentPageUrl(bookId,itemId,p);var cfg=JSON.stringify({isHideable:true,expandedCornersRadius:12,skipCollapsed:true,hardwareAccelerated:true,heightPercentage:0.8});var js='java.showBrowser('+JSON.stringify(url)+',null,null,'+JSON.stringify(cfg)+')';var opt={style:'TEXT',width:'36',js:'result',click:js,marker:'bookSource:fqtt:'+bookId+':'+itemId+':'+p};return '<img src="'+getBase()+'/comment-icon.png,'+JSON.stringify(opt)+'">';}
function addCommentEntries(content,bookId,itemId){var lines=String(content||'').replace(/\r/g,'').split('\n');var idx=0;for(var i=0;i<lines.length;i++){var line=String(lines[i]||'');var text=clean(line).replace(/^\s+|\s+$/g,'');if(!text)continue;var p=String(idx++);if(hasCommentMarker(line,bookId,itemId,p)||line.indexOf('paragraphRule:fqtt:'+bookId+':'+itemId+':'+p)>=0)continue;lines[i]=line+commentIcon(bookId,itemId,p,text);}return lines.join('\n');}
